from __future__ import annotations

import base64
import io
import os
import pickle
import threading
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import numpy as np
from fastapi import FastAPI, File, HTTPException, UploadFile
from fastapi.responses import JSONResponse
from PIL import Image

try:
    import face_recognition
except ImportError as e:
    raise RuntimeError(
        "The face_recognition package is required. Install with: pip install face_recognition"
    ) from e


APP_TITLE = "Face Recognition API"
DEFAULT_MODEL_PATH = Path(os.getenv("FACE_MODEL_PATH", "face_model.pkl"))
DEFAULT_TRAIN_DIR = Path(os.getenv("FACE_TRAIN_DIR", "training_images"))
DEFAULT_THRESHOLD = float(os.getenv("FACE_DISTANCE_THRESHOLD", "0.6"))


@dataclass
class FaceModel:
    encodings: np.ndarray
    labels: List[str]

    def save(self, path: Path) -> None:
        payload = {
            "encodings": self.encodings,
            "labels": self.labels,
        }
        path.parent.mkdir(parents=True, exist_ok=True)
        with path.open("wb") as f:
            pickle.dump(payload, f)

    @staticmethod
    def load(path: Path) -> "FaceModel":
        with path.open("rb") as f:
            payload = pickle.load(f)
        encodings = np.asarray(payload["encodings"], dtype=np.float32)
        labels = list(payload["labels"])
        return FaceModel(encodings=encodings, labels=labels)


class FaceRecognizer:
    def __init__(self, model_path: Path = DEFAULT_MODEL_PATH, threshold: float = DEFAULT_THRESHOLD):
        self.model_path = model_path
        self.threshold = threshold
        self._lock = threading.Lock()
        self.model: Optional[FaceModel] = None
        if self.model_path.exists():
            self.model = FaceModel.load(self.model_path)

    def _extract_single_face_encoding(self, image_bytes: bytes) -> np.ndarray:
        image = face_recognition.load_image_file(io.BytesIO(image_bytes))
        locations = face_recognition.face_locations(image, model="hog")
        if not locations:
            raise ValueError("No face detected in image")
        encodings = face_recognition.face_encodings(image, known_face_locations=locations)
        if not encodings:
            raise ValueError("Unable to compute face encoding")
        return np.asarray(encodings[0], dtype=np.float32)

    def train_from_directory(self, train_dir: Path) -> FaceModel:
        if not train_dir.exists() or not train_dir.is_dir():
            raise FileNotFoundError(f"Training directory not found: {train_dir}")

        encodings: List[np.ndarray] = []
        labels: List[str] = []

        for person_dir in sorted([p for p in train_dir.iterdir() if p.is_dir()]):
            label = person_dir.name
            for img_path in sorted(person_dir.glob("*")):
                if img_path.suffix.lower() not in {".jpg", ".jpeg", ".png", ".bmp", ".webp"}:
                    continue
                try:
                    image = face_recognition.load_image_file(str(img_path))
                    locations = face_recognition.face_locations(image, model="hog")
                    if not locations:
                        continue
                    face_encs = face_recognition.face_encodings(image, known_face_locations=locations)
                    for enc in face_encs:
                        encodings.append(np.asarray(enc, dtype=np.float32))
                        labels.append(label)
                except Exception:
                    continue

        if not encodings:
            raise ValueError("No training faces found")

        model = FaceModel(encodings=np.vstack(encodings), labels=labels)
        with self._lock:
            self.model = model
            self.model.save(self.model_path)
        return model

    def _softmax_from_distances(self, distances: np.ndarray) -> np.ndarray:
        x = -np.asarray(distances, dtype=np.float32)
        x = x - np.max(x)
        ex = np.exp(x)
        s = np.sum(ex)
        return ex / s if s > 0 else np.ones_like(ex) / len(ex)

    def recognize(self, image_bytes: bytes) -> Dict:
        with self._lock:
            if self.model is None:
                raise ValueError("Model is not trained")

            query = self._extract_single_face_encoding(image_bytes)
            distances = face_recognition.face_distance(self.model.encodings, query)

            label_to_distances: Dict[str, List[float]] = {}
            for label, dist in zip(self.model.labels, distances.tolist()):
                label_to_distances.setdefault(label, []).append(float(dist))

            label_scores: Dict[str, float] = {}
            label_best_distance: Dict[str, float] = {}
            for label, dists in label_to_distances.items():
                best = min(dists)
                label_best_distance[label] = best
                label_scores[label] = float(1.0 / (1.0 + best))

            labels_sorted = sorted(label_scores.keys())
            score_vector = np.array([label_scores[l] for l in labels_sorted], dtype=np.float32)
            probabilities = self._softmax_from_distances(1.0 - score_vector)

            distribution = {
                label: float(prob)
                for label, prob in zip(labels_sorted, probabilities.tolist())
            }

            best_label = max(distribution, key=distribution.get)
            best_probability = distribution[best_label]
            is_match = label_best_distance[best_label] <= self.threshold

            return {
                "match": bool(is_match),
                "best_label": best_label,
                "confidence": float(best_probability),
                "threshold": float(self.threshold),
                "distribution": distribution,
                "distances": {k: float(v) for k, v in label_best_distance.items()},
                "num_known_faces": len(labels_sorted),
            }


recognizer = FaceRecognizer(model_path=DEFAULT_MODEL_PATH, threshold=DEFAULT_THRESHOLD)
app = FastAPI(title=APP_TITLE)


@app.get("/health")
def health():
    return {"status": "ok", "model_loaded": recognizer.model is not None}


@app.post("/train")
def train():
    try:
        model = recognizer.train_from_directory(DEFAULT_TRAIN_DIR)
        return {
            "status": "trained",
            "num_samples": int(len(model.labels)),
            "num_classes": int(len(set(model.labels))),
            "model_path": str(recognizer.model_path),
        }
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


@app.post("/train/upload")
async def train_upload(label: str, file: UploadFile = File(...)):
    try:
        data = await file.read()
        image = face_recognition.load_image_file(io.BytesIO(data))
        locations = face_recognition.face_locations(image, model="hog")
        if not locations:
            raise ValueError("No face detected in uploaded image")
        encodings = face_recognition.face_encodings(image, known_face_locations=locations)
        if not encodings:
            raise ValueError("Unable to compute face encoding")

        with recognizer._lock:
            if recognizer.model is None:
                encs = []
                labels = []
            else:
                encs = [row for row in recognizer.model.encodings]
                labels = list(recognizer.model.labels)

            for enc in encodings:
                encs.append(np.asarray(enc, dtype=np.float32))
                labels.append(label)

            model = FaceModel(encodings=np.vstack(encs), labels=labels)
            recognizer.model = model
            model.save(recognizer.model_path)

        return {"status": "trained", "label": label, "samples_added": len(encodings)}
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


@app.post("/recognize")
async def recognize(file: UploadFile = File(...)):
    if recognizer.model is None:
        raise HTTPException(status_code=400, detail="Model is not trained")
    try:
        data = await file.read()
        result = recognizer.recognize(data)
        return JSONResponse(result)
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


@app.post("/recognize/base64")
def recognize_base64(payload: Dict):
    if recognizer.model is None:
        raise HTTPException(status_code=400, detail="Model is not trained")
    try:
        image_b64 = payload.get("image_base64")
        if not image_b64:
            raise ValueError("image_base64 is required")
        data = base64.b64decode(image_b64)
        result = recognizer.recognize(data)
        return JSONResponse(result)
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


@app.get("/classes")
def classes():
    if recognizer.model is None:
        return {"classes": []}
    counts: Dict[str, int] = {}
    for label in recognizer.model.labels:
        counts[label] = counts.get(label, 0) + 1
    return {
        "classes": sorted(counts.keys()),
        "counts": counts,
        "num_classes": len(counts),
    }